    right_valid[n-1] = true;
    for (int i = n-2; i >= 0; --i) {
        if (nums[i] > nums[i+1]) {
            right_valid[i] = right_valid[i+1];
        } else {
            break;
        }
    }

    // Compute prefix sum
    vector<long long> prefix(n+1, 0);
    for (int i = 0; i < n; ++i) {
        prefix[i+1] = prefix[i] + nums[i];
