    long long min_diff = LLONG_MAX;
    bool found = false;

    for (int i = 1; i < n; ++i) {
        if (left_valid[i-1] && right_valid[i]) {
            // Check if left is strictly increasing and right is strictly decreasing
            bool valid = true;
            // Check boundary condition
            if (i < n && nums[i-1] >= nums[i]) {
                valid = false;
            }
            if (valid) {
                long long left_sum = prefix[i];
                long long right_sum = prefix[n] - prefix[i];
                long long diff = abs(left_sum - right_sum);
                if (diff < min_diff) {
                    min_diff = diff;
